func writeORMUpdate(b *strings.Builder, msgName, tableName, _, pkCol string, fields []ormField, hasTenant, softDelete bool, tenantField *ormField, pkField *ormField, timestamps bool) {
	// See excludedFromSet for what never reaches the SET clause.
	excludeFromSet := func(f ormField) bool { return excludedFromSet(f, timestamps) }

	// Count updatable fields.
	updatableCount := 0
	for _, f := range fields {
		if excludeFromSet(f) {
			continue
		}
		updatableCount++
	}

	// If there are no updatable fields, generate a no-op function.
	if updatableCount == 0 {
		fmt.Fprintf(b, "// Update%s is a no-op because %s has no updatable fields.\n", msgName, msgName)
		if hasTenant {
			fmt.Fprintf(b, "func Update%s(_ context.Context, _ orm.Context, _ *%s, _ string) error {\n", msgName, msgName)
		} else {
			fmt.Fprintf(b, "func Update%s(_ context.Context, _ orm.Context, _ *%s) error {\n", msgName, msgName)
		}
		b.WriteString("\treturn nil // no updatable fields\n")
		b.WriteString("}\n\n")
		return
	}

	fmt.Fprintf(b, "// Update%s updates an existing %s by its primary key.\n", msgName, msgName)
	if timestamps {
		b.WriteString("//\n")
		b.WriteString("// updated_at is stamped here (timestamps: true); created_at is immutable\n")
		b.WriteString("// and excluded from the SET clause.\n")
	}
	if hasTenant {
		fmt.Fprintf(b, "func Update%s(ctx context.Context, db orm.Context, msg *%s, tenantID string) error {\n", msgName, msgName)
	} else {
		fmt.Fprintf(b, "func Update%s(ctx context.Context, db orm.Context, msg *%s) error {\n", msgName, msgName)
	}
	fmt.Fprintf(b, "\tctx, span := ormTracer.Start(ctx, \"orm.Update%s\",\n", msgName)
	fmt.Fprintf(b, "\t\ttrace.WithAttributes(attribute.String(\"table\", %q)))\n", tableName)
	b.WriteString("\tdefer span.End()\n\n")

	if timestamps {
		if writeUpdatedAtStamp(b, fields, "\t") {
			b.WriteString("\n")
		}
	}

	b.WriteString("\tdialect := db.Dialect()\n\n")

	// Build SET clause (see excludeFromSet for what stays out).
	type setCol struct {
		field ormField
		idx   int
	}
	var setCols []setCol
	for i, f := range fields {
		if excludeFromSet(f) {
			continue
		}
		setCols = append(setCols, setCol{field: f, idx: i})
	}

	b.WriteString("\tsetParts := []string{\n")
	for phIdx, sc := range setCols {
		fmt.Fprintf(b, "\t\tfmt.Sprintf(\"%%s = %%s\", dialect.QuoteIdentifier(%q), dialect.Placeholder(%d)),\n", sc.field.columnName, phIdx)
	}
	b.WriteString("\t}\n\n")

	// Build values for SET clause
	b.WriteString("\targs := []any{\n")
	for _, sc := range setCols {
		fmt.Fprintf(b, "\t\t%s,\n", valueExpr(sc.field))
	}
	b.WriteString("\t}\n\n")

	pkPlaceholderIdx := len(setCols)

	if softDelete && hasTenant {
		tenantPlaceholderIdx := pkPlaceholderIdx + 1
		b.WriteString("\tquery := fmt.Sprintf(\"UPDATE %s SET %s WHERE %s = %s AND %s IS NULL AND %s = %s\",\n")
		fmt.Fprintf(b, "\t\tdialect.QuoteIdentifier(%q),\n", tableName)
		b.WriteString("\t\tstrings.Join(setParts, \", \"),\n")
		fmt.Fprintf(b, "\t\tdialect.QuoteIdentifier(%q),\n", pkCol)
		fmt.Fprintf(b, "\t\tdialect.Placeholder(%d),\n", pkPlaceholderIdx)
		b.WriteString("\t\tdialect.QuoteIdentifier(\"deleted_at\"),\n")
		fmt.Fprintf(b, "\t\tdialect.QuoteIdentifier(%q),\n", tenantField.columnName)
		fmt.Fprintf(b, "\t\tdialect.Placeholder(%d),\n", tenantPlaceholderIdx)
		b.WriteString("\t)\n\n")
		// Append PK and tenant values
		if pkField != nil {
			fmt.Fprintf(b, "\targs = append(args, msg.%s, tenantID)\n", pkField.goName)
		} else {
			b.WriteString("\targs = append(args, msg.Id, tenantID)\n")
		}
	} else if softDelete {
		b.WriteString("\tquery := fmt.Sprintf(\"UPDATE %s SET %s WHERE %s = %s AND %s IS NULL\",\n")
		fmt.Fprintf(b, "\t\tdialect.QuoteIdentifier(%q),\n", tableName)
		b.WriteString("\t\tstrings.Join(setParts, \", \"),\n")
		fmt.Fprintf(b, "\t\tdialect.QuoteIdentifier(%q),\n", pkCol)
		fmt.Fprintf(b, "\t\tdialect.Placeholder(%d),\n", pkPlaceholderIdx)
		b.WriteString("\t\tdialect.QuoteIdentifier(\"deleted_at\"),\n")
		b.WriteString("\t)\n\n")
		if pkField != nil {
			fmt.Fprintf(b, "\targs = append(args, msg.%s)\n", pkField.goName)
		} else {
			b.WriteString("\targs = append(args, msg.Id)\n")
		}
	} else if hasTenant {
		tenantPlaceholderIdx := pkPlaceholderIdx + 1
		b.WriteString("\tquery := fmt.Sprintf(\"UPDATE %s SET %s WHERE %s = %s AND %s = %s\",\n")
		fmt.Fprintf(b, "\t\tdialect.QuoteIdentifier(%q),\n", tableName)
		b.WriteString("\t\tstrings.Join(setParts, \", \"),\n")
		fmt.Fprintf(b, "\t\tdialect.QuoteIdentifier(%q),\n", pkCol)
		fmt.Fprintf(b, "\t\tdialect.Placeholder(%d),\n", pkPlaceholderIdx)
		fmt.Fprintf(b, "\t\tdialect.QuoteIdentifier(%q),\n", tenantField.columnName)
		fmt.Fprintf(b, "\t\tdialect.Placeholder(%d),\n", tenantPlaceholderIdx)
		b.WriteString("\t)\n\n")
		if pkField != nil {
			fmt.Fprintf(b, "\targs = append(args, msg.%s, tenantID)\n", pkField.goName)
		} else {
			b.WriteString("\targs = append(args, msg.Id, tenantID)\n")
		}
	} else {
		// Simple case: no soft-delete, no tenant.
		b.WriteString("\tquery := fmt.Sprintf(\"UPDATE %s SET %s WHERE %s = %s\",\n")
		fmt.Fprintf(b, "\t\tdialect.QuoteIdentifier(%q),\n", tableName)
		b.WriteString("\t\tstrings.Join(setParts, \", \"),\n")
		fmt.Fprintf(b, "\t\tdialect.QuoteIdentifier(%q),\n", pkCol)
		fmt.Fprintf(b, "\t\tdialect.Placeholder(%d),\n", pkPlaceholderIdx)
		b.WriteString("\t)\n\n")
		if pkField != nil {
			fmt.Fprintf(b, "\targs = append(args, msg.%s)\n", pkField.goName)
		} else {
			b.WriteString("\targs = append(args, msg.Id)\n")
		}
	}

	b.WriteString("\n\t_, err := db.Exec(ctx, query, args...)\n")
	b.WriteString("\tif err != nil {\n")
	b.WriteString("\t\tspan.RecordError(err)\n")
	b.WriteString("\t\tspan.SetStatus(codes.Error, err.Error())\n")
	fmt.Fprintf(b, "\t\treturn fmt.Errorf(\"update %s: %%w\", err)\n", tableName)
	b.WriteString("\t}\n")
	b.WriteString("\treturn nil\n")
	b.WriteString("}\n\n")
}

// writeORMUpdateMasked emits Update<Entity>Masked — the AIP-134 partial
// update sibling of Update<Entity>. It writes ONLY the columns named in
// fields (proto field names == column names, snake_case), validates each
// path against the updatable set (same excludeFromSet rules as the full
// update: never the PK, tenant key, deleted_at, or — with managed
// timestamps — created_at), and returns *orm.UnknownFieldError for any
// path outside that set so pkg/crud can map it to InvalidArgument
// without leaking SQL. updated_at is stamped on masked updates too.
func writeORMUpdateMasked(b *strings.Builder, msgName, tableName, pkCol string, fields []ormField, hasTenant, softDelete bool, tenantField *ormField, pkField *ormField, timestamps bool) {
	excludeFromSet := func(f ormField) bool { return excludedFromSet(f, timestamps) }

	var updatable []ormField
	for _, f := range fields {
		if excludeFromSet(f) {
			continue
		}
		updatable = append(updatable, f)
	}

	sigSuffix := ") error {\n"
	if hasTenant {
		sigSuffix = ", tenantID string) error {\n"
	}

	// No updatable columns: a concrete mask path can only ever be
	// unknown; an empty mask is a no-op (mirrors Update<Entity>).
	if len(updatable) == 0 {
		fmt.Fprintf(b, "// Update%sMasked is a no-op shell because %s has no updatable fields;\n", msgName, msgName)
		b.WriteString("// any concrete update_mask path is therefore unknown.\n")
		if hasTenant {
			fmt.Fprintf(b, "func Update%sMasked(_ context.Context, _ orm.Context, _ *%s, fields []string, _ string) error {\n", msgName, msgName)
		} else {
			fmt.Fprintf(b, "func Update%sMasked(_ context.Context, _ orm.Context, _ *%s, fields []string) error {\n", msgName, msgName)
		}
		b.WriteString("\tif len(fields) > 0 {\n")
		b.WriteString("\t\treturn &orm.UnknownFieldError{Field: fields[0]}\n")
		b.WriteString("\t}\n")
		b.WriteString("\treturn nil\n")
		b.WriteString("}\n\n")
		return
	}

	fmt.Fprintf(b, "// Update%sMasked updates ONLY the named fields of an existing %s\n", msgName, msgName)
	b.WriteString("// (AIP-134 update_mask paths; proto field names == column names).\n")
	b.WriteString("// Paths outside the updatable set return *orm.UnknownFieldError —\n")
	b.WriteString("// forge/pkg/crud maps it to a clean InvalidArgument.\n")
	if timestamps {
		b.WriteString("//\n")
		b.WriteString("// updated_at is stamped here too (timestamps: true); created_at is\n")
		b.WriteString("// immutable and never settable through a mask.\n")
	}
	fmt.Fprintf(b, "func Update%sMasked(ctx context.Context, db orm.Context, msg *%s, fields []string%s", msgName, msgName, sigSuffix)
	b.WriteString("\tif len(fields) == 0 {\n")
	b.WriteString("\t\treturn nil\n")
	b.WriteString("\t}\n\n")
	fmt.Fprintf(b, "\tctx, span := ormTracer.Start(ctx, \"orm.Update%sMasked\",\n", msgName)
	fmt.Fprintf(b, "\t\ttrace.WithAttributes(attribute.String(\"table\", %q)))\n", tableName)
	b.WriteString("\tdefer span.End()\n\n")

	stampUpdatedAt := false
	if timestamps {
		stampUpdatedAt = writeUpdatedAtStamp(b, fields, "\t")
		if stampUpdatedAt {
			b.WriteString("\n")
		}
	}

	b.WriteString("\tdialect := db.Dialect()\n\n")

	b.WriteString("\t// The updatable-column set. Anything else (unknown columns, the PK,\n")
	b.WriteString("\t// the tenant key, immutable bookkeeping columns) is rejected.\n")
	b.WriteString("\tcolValue := map[string]any{\n")
	for _, f := range updatable {
		fmt.Fprintf(b, "\t\t%q: %s,\n", f.columnName, valueExpr(f))
	}
	b.WriteString("\t}\n\n")

	b.WriteString("\tsetParts := make([]string, 0, len(fields)+1)\n")
	b.WriteString("\targs := make([]any, 0, len(fields)+3)\n")
	b.WriteString("\tseen := make(map[string]bool, len(fields))\n")
	b.WriteString("\tfor _, f := range fields {\n")
	b.WriteString("\t\tv, ok := colValue[f]\n")
	b.WriteString("\t\tif !ok {\n")
	b.WriteString("\t\t\treturn &orm.UnknownFieldError{Field: f}\n")
	b.WriteString("\t\t}\n")
	b.WriteString("\t\tif seen[f] {\n")
	b.WriteString("\t\t\tcontinue\n")
	b.WriteString("\t\t}\n")
	b.WriteString("\t\tseen[f] = true\n")
	b.WriteString("\t\tsetParts = append(setParts, fmt.Sprintf(\"%s = %s\", dialect.QuoteIdentifier(f), dialect.Placeholder(len(args))))\n")
	b.WriteString("\t\targs = append(args, v)\n")
	b.WriteString("\t}\n")
	if stampUpdatedAt {
		b.WriteString("\tif !seen[\"updated_at\"] {\n")
		b.WriteString("\t\tsetParts = append(setParts, fmt.Sprintf(\"%s = %s\", dialect.QuoteIdentifier(\"updated_at\"), dialect.Placeholder(len(args))))\n")
		b.WriteString("\t\targs = append(args, msg.UpdatedAt)\n")
		b.WriteString("\t}\n")
	}
	b.WriteString("\n")

	pkValue := "msg.Id"
	if pkField != nil {
		pkValue = "msg." + pkField.goName
	}

	if softDelete && hasTenant {
		b.WriteString("\tquery := fmt.Sprintf(\"UPDATE %s SET %s WHERE %s = %s AND %s IS NULL AND %s = %s\",\n")
		fmt.Fprintf(b, "\t\tdialect.QuoteIdentifier(%q),\n", tableName)
		b.WriteString("\t\tstrings.Join(setParts, \", \"),\n")
		fmt.Fprintf(b, "\t\tdialect.QuoteIdentifier(%q),\n", pkCol)
		b.WriteString("\t\tdialect.Placeholder(len(args)),\n")
		b.WriteString("\t\tdialect.QuoteIdentifier(\"deleted_at\"),\n")
		fmt.Fprintf(b, "\t\tdialect.QuoteIdentifier(%q),\n", tenantField.columnName)
		b.WriteString("\t\tdialect.Placeholder(len(args)+1),\n")
		b.WriteString("\t)\n")
		fmt.Fprintf(b, "\targs = append(args, %s, tenantID)\n", pkValue)
	} else if softDelete {
		b.WriteString("\tquery := fmt.Sprintf(\"UPDATE %s SET %s WHERE %s = %s AND %s IS NULL\",\n")
		fmt.Fprintf(b, "\t\tdialect.QuoteIdentifier(%q),\n", tableName)
		b.WriteString("\t\tstrings.Join(setParts, \", \"),\n")
		fmt.Fprintf(b, "\t\tdialect.QuoteIdentifier(%q),\n", pkCol)
		b.WriteString("\t\tdialect.Placeholder(len(args)),\n")
		b.WriteString("\t\tdialect.QuoteIdentifier(\"deleted_at\"),\n")
		b.WriteString("\t)\n")
		fmt.Fprintf(b, "\targs = append(args, %s)\n", pkValue)
	} else if hasTenant {
		b.WriteString("\tquery := fmt.Sprintf(\"UPDATE %s SET %s WHERE %s = %s AND %s = %s\",\n")
		fmt.Fprintf(b, "\t\tdialect.QuoteIdentifier(%q),\n", tableName)
		b.WriteString("\t\tstrings.Join(setParts, \", \"),\n")
		fmt.Fprintf(b, "\t\tdialect.QuoteIdentifier(%q),\n", pkCol)
		b.WriteString("\t\tdialect.Placeholder(len(args)),\n")
		fmt.Fprintf(b, "\t\tdialect.QuoteIdentifier(%q),\n", tenantField.columnName)
		b.WriteString("\t\tdialect.Placeholder(len(args)+1),\n")
		b.WriteString("\t)\n")
		fmt.Fprintf(b, "\targs = append(args, %s, tenantID)\n", pkValue)
	} else {
		b.WriteString("\tquery := fmt.Sprintf(\"UPDATE %s SET %s WHERE %s = %s\",\n")
		fmt.Fprintf(b, "\t\tdialect.QuoteIdentifier(%q),\n", tableName)
		b.WriteString("\t\tstrings.Join(setParts, \", \"),\n")
		fmt.Fprintf(b, "\t\tdialect.QuoteIdentifier(%q),\n", pkCol)
		b.WriteString("\t\tdialect.Placeholder(len(args)),\n")
		b.WriteString("\t)\n")
		fmt.Fprintf(b, "\targs = append(args, %s)\n", pkValue)
	}

	b.WriteString("\n\t_, err := db.Exec(ctx, query, args...)\n")
	b.WriteString("\tif err != nil {\n")
	b.WriteString("\t\tspan.RecordError(err)\n")
	b.WriteString("\t\tspan.SetStatus(codes.Error, err.Error())\n")
	fmt.Fprintf(b, "\t\treturn fmt.Errorf(\"update %s: %%w\", err)\n", tableName)
	b.WriteString("\t}\n")
	b.WriteString("\treturn nil\n")
	b.WriteString("}\n\n")
}

func writeORMDelete(b *strings.Builder, msgName, tableName, pkCol, pkGoType string, fields []ormField, hasTenant, softDelete bool, tenantField *ormField) {
	if softDelete {
		fmt.Fprintf(b, "// Delete%s soft-deletes a %s by setting deleted_at.\n", msgName, msgName)
	} else {
		fmt.Fprintf(b, "// Delete%s permanently deletes a %s by its primary key.\n", msgName, msgName)
	}
	if hasTenant {
		fmt.Fprintf(b, "func Delete%s(ctx context.Context, db orm.Context, id %s, tenantID string) error {\n", msgName, pkGoType)
	} else {
		fmt.Fprintf(b, "func Delete%s(ctx context.Context, db orm.Context, id %s) error {\n", msgName, pkGoType)
	}
	fmt.Fprintf(b, "\tctx, span := ormTracer.Start(ctx, \"orm.Delete%s\",\n", msgName)
	b.WriteString("\t\ttrace.WithAttributes(\n")
	fmt.Fprintf(b, "\t\t\tattribute.String(\"table\", %q),\n", tableName)
	b.WriteString("\t\t\tattribute.String(\"id\", fmt.Sprint(id)),\n")
	b.WriteString("\t\t))\n")
	b.WriteString("\tdefer span.End()\n\n")

	if softDelete && hasTenant {
		b.WriteString("\t// Soft delete with tenant isolation.\n")
		b.WriteString("\tdialect := db.Dialect()\n")
		b.WriteString("\tquery := fmt.Sprintf(\"UPDATE %s SET %s = CURRENT_TIMESTAMP WHERE %s = %s AND %s IS NULL AND %s = %s\",\n")
		fmt.Fprintf(b, "\t\tdialect.QuoteIdentifier(%q),\n", tableName)
		b.WriteString("\t\tdialect.QuoteIdentifier(\"deleted_at\"),\n")
		fmt.Fprintf(b, "\t\tdialect.QuoteIdentifier(%q),\n", pkCol)
		b.WriteString("\t\tdialect.Placeholder(0),\n")
		b.WriteString("\t\tdialect.QuoteIdentifier(\"deleted_at\"),\n")
		fmt.Fprintf(b, "\t\tdialect.QuoteIdentifier(%q),\n", tenantField.columnName)
		b.WriteString("\t\tdialect.Placeholder(1),\n")
		b.WriteString("\t)\n")
		b.WriteString("\t_, err := db.Exec(ctx, query, id, tenantID)\n")
	} else if softDelete {
		b.WriteString("\t// Soft delete: set deleted_at instead of removing the row.\n")
		b.WriteString("\tdialect := db.Dialect()\n")
		b.WriteString("\tquery := fmt.Sprintf(\"UPDATE %s SET %s = CURRENT_TIMESTAMP WHERE %s = %s AND %s IS NULL\",\n")
		fmt.Fprintf(b, "\t\tdialect.QuoteIdentifier(%q),\n", tableName)
		b.WriteString("\t\tdialect.QuoteIdentifier(\"deleted_at\"),\n")
		fmt.Fprintf(b, "\t\tdialect.QuoteIdentifier(%q),\n", pkCol)
		b.WriteString("\t\tdialect.Placeholder(0),\n")
		b.WriteString("\t\tdialect.QuoteIdentifier(\"deleted_at\"),\n")
		b.WriteString("\t)\n")
		b.WriteString("\t_, err := db.Exec(ctx, query, id)\n")
	} else if hasTenant {
		b.WriteString("\t// Hard delete with tenant isolation.\n")
		b.WriteString("\tdialect := db.Dialect()\n")
		b.WriteString("\tquery := fmt.Sprintf(\"DELETE FROM %s WHERE %s = %s AND %s = %s\",\n")
		fmt.Fprintf(b, "\t\tdialect.QuoteIdentifier(%q),\n", tableName)
		fmt.Fprintf(b, "\t\tdialect.QuoteIdentifier(%q),\n", pkCol)
		b.WriteString("\t\tdialect.Placeholder(0),\n")
		fmt.Fprintf(b, "\t\tdialect.QuoteIdentifier(%q),\n", tenantField.columnName)
		b.WriteString("\t\tdialect.Placeholder(1),\n")
		b.WriteString("\t)\n")
		b.WriteString("\t_, err := db.Exec(ctx, query, id, tenantID)\n")
	} else {
		b.WriteString("\tdialect := db.Dialect()\n")
		b.WriteString("\tquery := fmt.Sprintf(\"DELETE FROM %s WHERE %s = %s\",\n")
		fmt.Fprintf(b, "\t\tdialect.QuoteIdentifier(%q),\n", tableName)
		fmt.Fprintf(b, "\t\tdialect.QuoteIdentifier(%q),\n", pkCol)
		b.WriteString("\t\tdialect.Placeholder(0),\n")
		b.WriteString("\t)\n")
		b.WriteString("\t_, err := db.Exec(ctx, query, id)\n")
	}

	b.WriteString("\tif err != nil {\n")
	b.WriteString("\t\tspan.RecordError(err)\n")
	b.WriteString("\t\tspan.SetStatus(codes.Error, err.Error())\n")
	fmt.Fprintf(b, "\t\treturn fmt.Errorf(\"delete %s: %%w\", err)\n", tableName)
	b.WriteString("\t}\n")
	b.WriteString("\treturn nil\n")
	b.WriteString("}\n")
}

// resolveORMFields converts PlanEntity fields (including auto-generated
// timestamp/soft-delete fields) into the ormField representation used
// by the code generator.
func resolveORMFields(ent config.PlanEntity) []ormField {
	type entry struct {
		config.PlanEntityField
		autoGenerated bool
	}

	// Check if any field already serves as the primary key.
	hasPK := false
	for _, f := range ent.Fields {
		if f.PrimaryKey || f.Name == "id" {
			hasPK = true
			break
		}
	}

	entries := make([]entry, 0, len(ent.Fields)+4)

	// Auto-add an id primary key field if none exists.
	if !hasPK {
		entries = append(entries, entry{PlanEntityField: config.PlanEntityField{
			Name: "id", Type: "string", PrimaryKey: true, NotNull: true,
		}})
	}

	declared := make(map[string]bool, len(ent.Fields))
	for _, f := range ent.Fields {
		declared[f.Name] = true
		entries = append(entries, entry{PlanEntityField: f})
	}

	// Auto-add timestamp/soft-delete columns ONLY when the entity didn't
	// declare them — proto entities routinely declare created_at /
	// updated_at / deleted_at explicitly alongside timestamps:true /
	// soft_delete:true, and a duplicate field is a compile error in the
	// generated code (duplicate consts) and a duplicate column in SQL.
	if ent.Timestamps {
		if !declared["created_at"] {
			entries = append(entries,
				entry{PlanEntityField: config.PlanEntityField{Name: "created_at", Type: "google.protobuf.Timestamp"}, autoGenerated: true})
		}
		if !declared["updated_at"] {
			entries = append(entries,
				entry{PlanEntityField: config.PlanEntityField{Name: "updated_at", Type: "google.protobuf.Timestamp"}, autoGenerated: true})
		}
	}
	if ent.SoftDelete && !declared["deleted_at"] {
		entries = append(entries,
			entry{PlanEntityField: config.PlanEntityField{Name: "deleted_at", Type: "google.protobuf.Timestamp"}, autoGenerated: true},
		)
	}

	fields := make([]ormField, 0, len(entries))
	for _, e := range entries {
		f := ormField{
			planField:   e.PlanEntityField,
			goName:      naming.ToProtoPascalCase(e.Name),
			columnName:  e.Name,
			goType:      planFieldGoType(e.Type),
			ormType:     planFieldOrmType(e.Type),
			isTimestamp: isTimePlanType(e.Type),
			isArray:     strings.HasPrefix(e.Type, "[]"),
			isPK:        e.PrimaryKey,
			isTenantKey: e.TenantKey,
			notNull:     e.NotNull,
			unique:      e.Unique,
			references:  e.References,
		}
		// Nullable column → pointer struct field. Arrays and bytes are
		// reference types already (NULL scans to nil).
		f.nullable = !f.isPK && !f.notNull && isNullablePlanType(e.Type)
		fields = append(fields, f)
	}
	return fields
}

// isTimePlanType reports whether the plan type is a timestamp column.
func isTimePlanType(t string) bool {
	switch t {
	case "time", "google.protobuf.Timestamp", "timestamp":
		return true
	}
	return false
}

// planFieldGoType maps a PlanEntityField.Type to the base Go type used
// on the entity struct (and in Values/Scan).
//
// The vocabulary is the canonical schema vocabulary (see
// internal/schemadef.MapDeclaredType): string, int64, float64, bool,
// time, json, bytes, []string, []int64. Legacy proto-type aliases stay
// mapped during the transition.
func planFieldGoType(t string) string {
	switch t {
	case "[]string":
		return "[]string"
	case "[]int64", "[]int", "[]int32":
		return "[]int64"
	case "string", "json":
		return "string"
	case "int32":
		return "int32"
	case "int64", "int":
		return "int64"
	case "uint32":
		return "uint32"
	case "uint64":
		return "uint64"
	case "bool":
		return "bool"
	case "float", "float32":
		return "float32"
	case "double", "float64":
		return "float64"
	case "bytes":
		return "[]byte"
	case "time", "google.protobuf.Timestamp", "timestamp":
		return "time.Time"
	default:
		return "string"
	}
}

// planFieldOrmType maps a PlanEntityField.Type to the orm.TypeXxx constant string
// used in generated Schema() code.
func planFieldOrmType(t string) string {
	if strings.HasPrefix(t, "[]") {
		return "orm.TypeJSONB"
	}
	switch t {
	case "string":
		return "orm.TypeText"
	case "json":
		return "orm.TypeJSONB"
	case "bool":
		return "orm.TypeBoolean"
	case "int32", "uint32":
		return "orm.TypeInteger"
	case "int64", "int", "uint64":
		return "orm.TypeBigInt"
	case "float", "float32":
		return "orm.TypeReal"
	case "double", "float64":
		return "orm.TypeDoublePrecision"
	case "bytes":
		return "orm.TypeBytea"
	case "time", "google.protobuf.Timestamp", "timestamp":
		return "orm.TypeTimestampTZ"
	default:
		return "orm.TypeText"
	}
}

// isNullablePlanType returns true when a nullable column of this type
// becomes a pointer field on the entity struct.
func isNullablePlanType(t string) bool {
	if strings.HasPrefix(t, "[]") || t == "bytes" {
		// Reference types: NULL scans to nil without a pointer.
		return false
	}
	switch t {
	case "string", "json", "int32", "int64", "int", "uint32", "uint64", "bool",
		"float", "float32", "double", "float64",
		"time", "google.protobuf.Timestamp", "timestamp":
		return true
	default:
		return false
	}
}
